FORM VALIDATION LIBRARY IMPLEMENTATION:

```typescript
// types.ts
export interface ValidationError {
  path: string[];
  message: string;
  code: string;
}

export type ValidationResult<T> = 
  | { success: true; data: T }
  | { success: false; errors: ValidationError[] };

export type ValidatorFn<T> = (value: T) => boolean | Promise<boolean>;

export interface ValidatorConfig {
  message?: string;
  code?: string;
}

// validators.ts
export class Validator<T> {
  private validators: Array<{ fn: ValidatorFn<T>; config: ValidatorConfig }> = [];
  private asyncValidators: Array<{ fn: ValidatorFn<T>; config: ValidatorConfig }> = [];

  pipe(...validators: Array<{ fn: ValidatorFn<T>; config: ValidatorConfig }>): this {
    validators.forEach(v => {
      const isAsync = v.fn.constructor.name === 'AsyncFunction';
      if (isAsync) {
        this.asyncValidators.push(v);
      } else {
        this.validators.push(v);
      }
    });
    return this;
  }

  async validate(value: T): Promise<ValidationError[]> {
    const errors: ValidationError[] = [];

    // Sync validators
    for (const { fn, config } of this.validators) {
      if (!fn(value)) {
        errors.push({ path: [], message: config.message || 'validation.invalid', code: config.code || 'INVALID' });
      }
    }

    // Async validators
    for (const { fn, config } of this.asyncValidators) {
      const result = await fn(value);
      if (!result) {
        errors.push({ path: [], message: config.message || 'validation.invalid', code: config.code || 'INVALID' });
      }
    }

    return errors;
  }
}

export const string = () => new Validator<string>();
export const number = () => new Validator<number>();
export const boolean = () => new Validator<boolean>();

// Built-in validators
export const required = () => ({ fn: (v: any) => v !== null && v !== undefined && v !== '', config: { message: 'validation.required', code: 'REQUIRED' } });
export const minLength = (min: number) => ({ fn: (v: string) => v.length >= min, config: { message: `validation.minLength:${min}`, code: 'MIN_LENGTH' } });
export const maxLength = (max: number) => ({ fn: (v: string) => v.length <= max, config: { message: `validation.maxLength:${max}`, code: 'MAX_LENGTH' } });
export const email = () => ({ fn: (v: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v), config: { message: 'validation.email', code: 'EMAIL' } });
export const pattern = (regex: RegExp) => ({ fn: (v: string) => regex.test(v), config: { message: 'validation.pattern', code: 'PATTERN' } });
export const min = (min: number) => ({ fn: (v: number) => v >= min, config: { message: `validation.min:${min}`, code: 'MIN' } });
export const max = (max: number) => ({ fn: (v: number) => v <= max, config: { message: `validation.max:${max}`, code: 'MAX' } });
export const oneOf = (values: any[]) => ({ fn: (v: any) => values.includes(v), config: { message: 'validation.oneOf', code: 'ONE_OF' } });

// object.ts
export class ObjectValidator<T extends Record<string, any>> extends Validator<T> {
  private schema: Record<string, Validator<any>> = {};
  private refinements: Array<{ fn: (data: T) => boolean; config: ValidatorConfig & { path: string[] } }> = [];

  constructor(schema: Record<string, Validator<any>>) {
    super();
    this.schema = schema;
  }

  refine(fn: (data: T) => boolean, config: ValidatorConfig & { path: string[] }): this {
    this.refinements.push({ fn, config });
    return this;
  }

  async validate(value: T): Promise<ValidationError[]> {
    const errors: ValidationError[] = [];

    // Validate each field
    for (const [key, validator] of Object.entries(this.schema)) {
      const fieldErrors = await validator.validate(value[key]);
      fieldErrors.forEach(err => {
        errors.push({ ...err, path: [key, ...err.path] });
      });
    }

    // Refinements (cross-field validation)
    for (const { fn, config } of this.refinements) {
      if (!fn(value)) {
        errors.push({ path: config.path, message: config.message || 'validation.invalid', code: config.code || 'REFINEMENT' });
      }
    }

    return errors;
  }
}

export const object = <T extends Record<string, any>>(schema: Record<string, Validator<any>>) => new ObjectValidator<T>(schema);

// array.ts
export class ArrayValidator<T> extends Validator<T[]> {
  private itemValidator: Validator<T>;

  constructor(itemValidator: Validator<T>) {
    super();
    this.itemValidator = itemValidator;
  }

  async validate(value: T[]): Promise<ValidationError[]> {
    const errors: ValidationError[] = [];

    for (let i = 0; i < value.length; i++) {
      const itemErrors = await this.itemValidator.validate(value[i]);
      itemErrors.forEach(err => {
        errors.push({ ...err, path: [String(i), ...err.path] });
      });
    }

    return errors;
  }
}

export const array = <T>(itemValidator: Validator<T>) => new ArrayValidator<T>(itemValidator);

// async helper
export const async = <T>(fn: ValidatorFn<T>) => ({ fn, config: { message: 'validation.invalid', code: 'ASYNC' } });

// Main validation function
export const validate = async <T>(schema: ObjectValidator<T>, data: unknown): Promise<ValidationResult<T>> => {
  const errors = await schema.validate(data as T);
  if (errors.length > 0) {
    return { success: false, errors };
  }
  return { success: true, data: data as T };
};

// Type inference helper
export type InferType<T extends ObjectValidator<any>> = T extends ObjectValidator<infer U> ? U : never;

